queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:specimenType ?cg . ?child a :Specimens ; p:type ?cg . ?l p:geologistId ?pg . ?parent a :Geologists ; p:id ?pg . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Geologists } }
  FILTER(?nf = ?total)
}

